def expand_dependencies(graph, selected_functions):

    visited = set()
    result = []

    def dfs(func):

        if func in visited:
            return

        visited.add(func)
        result.append(func)

        for dep in graph.get(func, []):
            dfs(dep)

    for func in selected_functions:
        dfs(func)

    return result

