def extract_attribute_ownerships(tree):
    """
    Extracts mappings like:

    self.router: APIRouter = APIRouter(...)
    self.router = APIRouter(...)

    Returns:

    {
        "FastAPI.router": "APIRouter"
    }
    """

    ownerships = {}

    for node in tree.body:

        if not isinstance(node, ast.ClassDef):
            continue

        class_name = node.name

        for item in node.body:

            if not isinstance(
                item,
                (
                    ast.FunctionDef,
                    ast.AsyncFunctionDef,
                ),
            ):
                continue

            for child in ast.walk(item):

                # ---------------------------------
                # self.router: APIRouter = ...
                # ---------------------------------
                if isinstance(child, ast.AnnAssign):

                    target = child.target

                    if (
                        isinstance(target, ast.Attribute)
                        and isinstance(
                            target.value,
                            ast.Name,
                        )
                        and target.value.id == "self"
                    ):

                        attr_name = target.attr

                        owner = _extract_annotation_name(
                            child.annotation
                        )

                        if owner:
                            ownerships[
                                f"{class_name}.{attr_name}"
                            ] = owner

                # ---------------------------------
                # self.router = APIRouter(...)
                # ---------------------------------
                elif isinstance(child, ast.Assign):

                    for target in child.targets:

                        if (
                            isinstance(
                                target,
                                ast.Attribute,
                            )
                            and isinstance(
                                target.value,
                                ast.Name,
                            )
                            and target.value.id
                            == "self"
                        ):

                            attr_name = (
                                target.attr
                            )

                            owner = (
                                _extract_call_owner(
                                    child.value
                                )
                            )

                            if owner:
                                ownerships[
                                    f"{class_name}.{attr_name}"
                                ] = owner

    return ownerships

