def _lookup(
    called_name,
    local_name_to_id,
    import_map,
    all_functions,
    repo_path,
):
    """
    helper()

    imported_function()
    """

    if called_name in local_name_to_id:
        return local_name_to_id[
            called_name
        ]

    if called_name in import_map:

        source_file = import_map[
            called_name
        ]

        relative_source = (
            "./"
            + os.path.relpath(
                source_file,
                repo_path,
            )
        )

        candidate = (
            f"{relative_source}:{called_name}"
        )

        if candidate in all_functions:
            return candidate

    return None

