def get_blast_radius(graph, changed_function):

    affected = set()

    def dfs(target):

        for function, dependencies in graph.items():

            if target in dependencies:

                if function not in affected:

                    affected.add(function)

                    dfs(function)

    dfs(changed_function)

    return list(affected)

